#!/usr/bin/env node

import { spawn } from 'node:child_process';
import { copyFile, mkdir, mkdtemp, rm, writeFile } from 'node:fs/promises';
import { tmpdir } from 'node:os';
import { dirname, extname, join, resolve } from 'node:path';
import { fileURLToPath } from 'node:url';
import { execFileSync } from 'node:child_process';

const __filename = fileURLToPath(import.meta.url);
const __dirname = dirname(__filename);
const repoRoot = resolve(__dirname, '..', '..');

const SUPPORTED_EXTENSIONS = new Set(['.js', '.jsx', '.ts', '.tsx', '.mjs', '.cjs', '.mts', '.cts']);
const ALWAYS_IGNORED_SEGMENTS = new Set([
  '.git',
  'node_modules',
  'dist',
  'build',
  'coverage',
  '.next',
  '.nx',
  'storybook-static',
  '__snapshots__',
  '__mocks__',
]);

const GENERATED_SEGMENTS = new Set(['generated', '__generated__']);

function parseArgs(argv) {
  const passthroughIndex = argv.indexOf('--');
  const ownArgs = passthroughIndex === -1 ? argv : argv.slice(0, passthroughIndex);
  const fallowArgs = passthroughIndex === -1 ? [] : argv.slice(passthroughIndex + 1);

  const options = {
    keepTemp: false,
    includeTests: false,
    includeGenerated: false,
    mode: 'semantic',
    minLines: '8',
    ignoreImports: true,
    quiet: false,
  };

  for (let index = 0; index < ownArgs.length; index += 1) {
    const arg = ownArgs[index];
    const next = ownArgs[index + 1];

    switch (arg) {
      case '--keep-temp':
        options.keepTemp = true;
        break;
      case '--include-tests':
        options.includeTests = true;
        break;
      case '--include-generated':
        options.includeGenerated = true;
        break;
      case '--mode':
        if (!next) {
          throw new Error('--mode requires a value');
        }
        options.mode = next;
        index += 1;
        break;
      case '--min-lines':
        if (!next) {
          throw new Error('--min-lines requires a value');
        }
        options.minLines = next;
        index += 1;
        break;
      case '--no-ignore-imports':
        options.ignoreImports = false;
        break;
      case '--quiet':
        options.quiet = true;
        break;
      case '-h':
      case '--help':
        printHelp();
        process.exit(0);
      default:
        throw new Error(`Unknown argument: ${arg}`);
    }
  }

  return { options, fallowArgs };
}

function printHelp() {
  console.log(`Run fallow duplication analysis only on files inside folders whose name contains "bw-react".

Usage:
  node tools/fallow/run-bw-react-dupes.mjs [options] [-- <extra fallow args>]

Options:
  --mode <mode>              Fallow duplicate mode (default: semantic)
  --min-lines <number>       Minimum duplicated lines (default: 8)
  --keep-temp                Keep the temporary filtered workspace
  --include-tests            Include __tests__, *.test.*, and *.spec.* files
  --include-generated        Include generated/__generated__ files
  --no-ignore-imports        Do not pass --ignore-imports to fallow
  --quiet                    Reduce script logging
  -h, --help                 Show this help

Examples:
  node tools/fallow/run-bw-react-dupes.mjs
  node tools/fallow/run-bw-react-dupes.mjs -- --summary
  node tools/fallow/run-bw-react-dupes.mjs --mode weak --min-lines 12 -- --format json
`);
}

function runGit(args) {
  return execFileSync('git', ['-C', repoRoot, ...args], {
    encoding: 'utf8',
    stdio: ['ignore', 'pipe', 'pipe'],
    maxBuffer: 64 * 1024 * 1024,
  });
}

function isInsideBwReactFolder(relativePath) {
  const parts = relativePath.split('/');
  return parts.slice(0, -1).some((part) => part.includes('bw-react'));
}

function getBwReactRoot(relativePath) {
  const parts = relativePath.split('/');
  const index = parts.findIndex((part) => part.includes('bw-react'));
  return index === -1 ? null : parts.slice(0, index + 1).join('/');
}

function shouldIncludeFile(relativePath, options) {
  const normalizedPath = relativePath.replace(/\\/g, '/');
  const parts = normalizedPath.split('/');
  const fileName = parts.at(-1) ?? '';
  const extension = extname(fileName).toLowerCase();

  if (!SUPPORTED_EXTENSIONS.has(extension)) {
    return false;
  }

  if (!isInsideBwReactFolder(normalizedPath)) {
    return false;
  }

  if (parts.some((part) => ALWAYS_IGNORED_SEGMENTS.has(part))) {
    return false;
  }

  if (!options.includeGenerated && parts.some((part) => GENERATED_SEGMENTS.has(part))) {
    return false;
  }

  if (/\.(stories|story)\.[^.]+$/i.test(fileName)) {
    return false;
  }

  if (!options.includeTests) {
    if (parts.includes('__tests__')) {
      return false;
    }

    if (/\.(test|spec)\.[^.]+$/i.test(fileName)) {
      return false;
    }
  }

  return true;
}

async function copySelectedFiles(files, tempRoot) {
  for (const relativePath of files) {
    const sourcePath = resolve(repoRoot, relativePath);
    const destinationPath = join(tempRoot, relativePath);
    await mkdir(dirname(destinationPath), { recursive: true });
    await copyFile(sourcePath, destinationPath);
  }
}

async function main() {
  const { options, fallowArgs } = parseArgs(process.argv.slice(2));

  const gitOutput = runGit(['ls-files', '-co', '--exclude-standard']);
  const candidateFiles = gitOutput
    .split('\n')
    .map((line) => line.trim())
    .filter(Boolean);

  const selectedFiles = [];
  const bwReactRoots = new Set();

  for (const relativePath of candidateFiles) {
    if (!shouldIncludeFile(relativePath, options)) {
      continue;
    }

    selectedFiles.push(relativePath);
    const root = getBwReactRoot(relativePath);
    if (root) {
      bwReactRoots.add(root);
    }
  }

  if (selectedFiles.length === 0) {
    console.error('No matching bw-react source files found after filtering.');
    process.exit(1);
  }

  const tempRoot = await mkdtemp(join(tmpdir(), 'fallow-bw-react-'));
  let cleanedUp = false;

  const cleanup = async () => {
    if (cleanedUp || options.keepTemp) {
      return;
    }

    cleanedUp = true;
    await rm(tempRoot, { recursive: true, force: true });
  };

  process.on('SIGINT', async () => {
    await cleanup();
    process.exit(130);
  });

  process.on('SIGTERM', async () => {
    await cleanup();
    process.exit(143);
  });

  await copySelectedFiles(selectedFiles, tempRoot);

  const manifest = {
    repoRoot,
    tempRoot,
    selectedFileCount: selectedFiles.length,
    bwReactRootCount: bwReactRoots.size,
    bwReactRoots: [...bwReactRoots].sort(),
    filters: {
      mode: options.mode,
      minLines: options.minLines,
      ignoreImports: options.ignoreImports,
      includeTests: options.includeTests,
      includeGenerated: options.includeGenerated,
    },
  };

  await writeFile(join(tempRoot, '.fallow-bw-react-selection.json'), JSON.stringify(manifest, null, 2));

  if (!options.quiet) {
    console.log(`Created filtered workspace: ${tempRoot}`);
    console.log(`Included bw-react roots: ${bwReactRoots.size}`);
    console.log(`Included source files: ${selectedFiles.length}`);
    console.log('Running fallow dupes on filtered workspace...');
  }

  const args = ['-y', 'fallow', 'dupes', '--root', tempRoot, '--mode', options.mode, '--min-lines', options.minLines];

  if (options.ignoreImports) {
    args.push('--ignore-imports');
  }

  args.push(...fallowArgs);

  const exitCode = await new Promise((resolvePromise, rejectPromise) => {
    const child = spawn('npx', args, {
      cwd: repoRoot,
      stdio: 'inherit',
      env: process.env,
    });

    child.on('error', rejectPromise);
    child.on('close', (code) => resolvePromise(code ?? 1));
  });

  if (options.keepTemp) {
    console.log(`Kept filtered workspace: ${tempRoot}`);
  } else {
    await cleanup();
  }

  process.exit(exitCode);
}

main().catch(async (error) => {
  console.error(error instanceof Error ? error.message : error);
  process.exit(1);
});

